con:mockOperation.con:dispatchPath:
import com.eviware.soapui.support.XmlHolder
import com.eviware.soapui.impl.wsdl.support.wsdl.WsdlContext
import com.eviware.soapui.impl.wsdl.support.wsdl.WsdlValidator
import com.eviware.soapui.impl.wsdl.panels.mockoperation.WsdlMockRequestMessageExchange

synchronized(mockRequest.context.mockService){

mh = new se.skl.rivta.tksupport.soapui.MockHelper(mockRequest, mockOperation)
context.validationMessages = mh.getSchemaErrorsInRequest() ?: mh.getEmptyElementsInRequest() ?: null
if (context.validationMessages) {
	return "SoapFault"
}

def holder = new XmlHolder( mockRequest.requestContent )
holder.namespaces['soapenv'] = 'http://schemas.xmlsoap.org/soap/envelope/'
holder.namespaces['urn'] = 'urn:riv:itintegration:registry:1'
holder.namespaces['urn1'] = 'urn:riv:clinicalprocess:healthcond:actoutcome:GetImagingOutcomeResponder:1'
holder.namespaces['urn2'] = 'urn:riv:clinicalprocess:healthcond:actoutcome:3'

def careUnitHSAId = holder.getNodeValue('/soapenv:Envelope/soapenv:Body/urn1:GetImagingOutcome/urn1:careUnitHSAId')
def patientId = holder.getNodeValue('/soapenv:Envelope/soapenv:Body/urn1:GetImagingOutcome/urn1:patientId/urn2:id')
def patientIdType = holder.getNodeValue('/soapenv:Envelope/soapenv:Body/urn1:GetImagingOutcome/urn1:patientId/urn2:type')

context.patientId = patientId
context.patientIdType = patientIdType
context.careUnitHSAId = careUnitHSAId

if (mockRequest.requestHeaders['x-mock-response'] != null){
	return mockRequest.requestHeaders['x-mock-response'][0]
}
else{
	//Kontrollera schema och schematron för request
	mh = new se.skl.rivta.tksupport.soapui.MockHelper(mockRequest, mockOperation, log)
	def validationErrors = mh.getSchemaErrorsInRequest() ?: mh.getSchematronErrorsInRequest("constraints.xml")
	if (validationErrors != null){
		context.validationMessages = validationErrors.toString()
		return "Response ERROR"
	}
}

}

